import productsData from "../data/ProductData";

const PopularProducts = () => {
  if (!productsData || productsData.length === 0) {
    return <h2 style={{ textAlign: "center" }}>⚠ No products found</h2>;
  }

  const popularItems = productsData.slice(0, 8);

  return (
    <section style={{ padding: "40px" }}>
      {/* Popular Products */}
      <h2 style={{ textAlign: "center", marginBottom: "20px" }}>
        🔥 Popular Products
      </h2>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(4, 1fr)", // ✅ 4 items per row
          gap: "25px",
          maxWidth: "1200px",
          margin: "0 auto",
        }}
      >
        {popularItems.map((item) => (
          <div key={item.id} style={{ textAlign: "center" }}>
            {/* Image box */}
            <div
              style={{
                border: "1px solid #ddd",
                padding: "15px",
                background: "#fff",
                height: "200px",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
              }}
            >
              <img
                src={item.image}
                alt={item.name}
                style={{
                  maxWidth: "100%",
                  maxHeight: "180px",
                  objectFit: "contain",
                }}
              />
            </div>

            {/* Product details */}
            <h3
              style={{
                fontSize: "14px", // ✅ smaller font
                margin: "10px 0 5px",
                fontFamily: "'Poppins', sans-serif",
              }}
            >
              {item.name}
            </h3>
            <p style={{ fontWeight: "bold", margin: "5px 0" }}>${item.price}</p>

            {/* ✅ Ratings (unchanged style) */}
            <p style={{ fontSize: "13px", color: "#f39c12" }}>⭐ {item.rating}</p>

            <button
              style={{
                marginTop: "8px",
                padding: "8px 15px",
                border: "none",
                borderRadius: "6px",
                background: "#9d5b2eff",
                color: "#fff",
                cursor: "pointer",
              }}
            >
              Buy Now
            </button>
          </div>
        ))}
      </div>

      {/* 🎮 Gaming Banner Section */}
      <div
        style={{
          marginTop: "50px",
          padding: "40px",
          borderRadius: "12px",
          background: "#f2f4f8",
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          flexWrap: "wrap",
        }}
      >
        {/* Left Image */}
        <img
          src="/images/products/sonyspeaker.jpg"
          alt="Gaming Speaker"
          style={{ maxWidth: "200px", borderRadius: "8px" }}
        />

        {/* Text Section */}
        <div style={{ textAlign: "center", flex: "1", padding: "20px" }}>
          <h2 style={{ fontSize: "22px", fontWeight: "bold", marginBottom: "10px" }}>
            Level Up Your Gaming Experience
          </h2>
          <p style={{ fontSize: "14px", color: "#555", marginBottom: "15px" }}>
            From immersive sound to precise controls—everything you need to win
          </p>
          <button
            style={{
              padding: "10px 20px",
              border: "none",
              borderRadius: "6px",
              background: "#f05a28",
              color: "#fff",
              fontSize: "14px",
              cursor: "pointer",
            }}
          >
            Buy now →
          </button>
        </div>

        {/* Right Image */}
        <img
          src="/images/products/controller.png"
          alt="Gaming Controller"
          style={{ maxWidth: "200px", borderRadius: "8px" }}
        />
      </div>
    </section>
  );
};

export default PopularProducts;
